+        let op2 = VdbeOp {
+            opcode: Opcode::Noop,
+            p1: 0,
+            p2: 0,
+            p3: 0,
+            p4: P4::None,
+            p5: u16::MAX,
+        };
+        assert_eq!(op2.p5, 65535);
+    }
